#![allow(warnings)]
use std::sync::Arc;
use std::thread;

struct BasicNode0 {
    value: i32,
}

fn test_value0() -> i32 {
    let n = BasicNode0 { value: 0 };
    n.value
}

fn test_rule1_0() -> Arc<BasicNode0> {
    let n = Arc::new(BasicNode0 { value: 0 });
    n
}

fn test_rule2_0() {
    let x = Arc::new(100);
    let x_clone = x.clone();
    let f = move |y: i32| -> i32 {
        *x_clone + y
    };
}

fn test_rule4_0() {
    let shared = Arc::new(BasicNode0 { value: 0 });
    let shared_clone = shared.clone();
    thread::spawn(move || {
        println!("{}", shared_clone.value);
    });
}

struct RecNode0 {
    value: i32,
    next: Option<Box<RecNode0>>,
}

fn test_rule5_0() {
    let r = RecNode0 { value: 0, next: None };
}

fn test_ifelse_0() {
    if 1 == 1 {
        println!("1");
    } else {
        println!("0");
    }
}

fn test_while_0() {
    let mut count = 0;
    while count < 10 {
        count += 1;
    }
}

fn test_nested_closures_0() {
    let x = Arc::new(10);
    let x_clone1 = x.clone();
    let f = move || {
        let y = Arc::new(20);
        let y_clone = y.clone();
        let x_clone2 = x_clone.clone();
        let g = move || {
            println!("{}", *x_clone2 + *y_clone);
        };
    };
}

fn test_rule3_0() {
    let n = Arc::new(BasicNode0 { value: 0 });
    let lst = vec![n.clone()];
}

fn test_relational_0() {
    let a = 5;
    let b = 10;
    let c = a < b;
}

